mapper.insert:
insert into hotel_order (
    user_id, hotel_id, room_id, check_in_date, check_out_date, total_amount, order_status
) values (
    #{userId}, #{hotelId}, #{roomId}, #{checkInDate}, #{checkOutDate}, #{totalAmount}, #{orderStatus}
)

mapper.select:
select id, user_id, hotel_id, room_id, check_in_date, check_out_date, total_amount, order_status, create_time
from hotel_order
where id = #{id}

mapper.update:
update hotel_order
set order_status = #{orderStatus}
where id = #{id}

mapper.select:
select count(*)
from hotel_order
where room_id = #{roomId}
  and order_status in ('CREATED', 'PAID', 'FINISHED')
  and check_in_date < #{checkOutDate}
  and check_out_date > #{checkInDate}
